css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { min-height: 100vh; display: flex; align-items: center; justify-content: center; background: radial-gradient(ellipse at top, #131736 0%, #070b18 60%); padding: 24px; }
.card { width: 100%; max-width: 460px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 24px; padding: 32px; backdrop-filter: blur(20px); box-shadow: 0 30px 60px rgba(0,0,0,0.4); position: relative; }
h1 { color: white; font-size: 24px; font-weight: 700; }
.sub { color: rgba(255,255,255,0.5); font-size: 13px; margin-top: 6px; margin-bottom: 26px; }
.group { margin-bottom: 22px; }
.group-title { color: #818cf8; font-size: 12px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; margin-bottom: 10px; }
.row { display: flex; align-items: center; justify-content: space-between; padding: 14px 0; border-bottom: 1px solid rgba(255,255,255,0.06); gap: 14px; }
.row:last-child { border-bottom: none; }
.row-text { display: flex; flex-direction: column; gap: 3px; }
.row-text .title { color: white; font-size: 14.5px; font-weight: 600; }
.row-text .desc { color: rgba(255,255,255,0.4); font-size: 12px; }
.switch { position: relative; display: inline-block; width: 46px; height: 26px; flex-shrink: 0; }
.switch input { opacity: 0; width: 0; height: 0; }
.slider { position: absolute; cursor: pointer; inset: 0; background: rgba(255,255,255,0.12); border-radius: 999px; transition: 0.2s; }
.slider:before { content: ""; position: absolute; height: 20px; width: 20px; left: 3px; bottom: 3px; background: white; border-radius: 50%; transition: 0.2s; }
input:checked + .slider { background: linear-gradient(135deg, #6366f1, #818cf8); }
input:checked + .slider:before { transform: translateX(20px); }
.select-row { align-items: center; }
select { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: white; padding: 9px 14px; border-radius: 10px; font-size: 13px; outline: none; }
.save-btn { width: 100%; padding: 15px; border: none; border-radius: 12px; background: linear-gradient(135deg, #6366f1, #818cf8); color: white; font-size: 15px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(99,102,241,0.3); margin-top: 8px; }
.toast { position: absolute; bottom: -50px; left: 50%; transform: translateX(-50%); background: #22c55e; color: white; padding: 10px 22px; border-radius: 999px; font-size: 13px; font-weight: 600; white-space: nowrap; opacity: 0; transition: 0.3s; }
.toast.show { opacity: 1; bottom: -56px; }
.toast.hidden { display: none; }

js:
const toast = document.getElementById('toast');

function save() {
  toast.classList.remove('hidden');
  requestAnimationFrame(() => toast.classList.add('show'));
  setTimeout(() => {
    toast.classList.remove('show');
    setTimeout(() => toast.classList.add('hidden'), 300);
  }, 2000);
}
